+    let (sidecar, proof) = generate_raptorq_sidecar(payload.as_str(), 4)?;
+
+    let sidecar_json = json!({
+        "artifact_id": format!("{packet_id}-parity-report"),
+        "artifact_type": "conformance",
+        "source_hash": sidecar.source_hash,
