+#[must_use]
+pub fn contiguous_strides(shape: &[usize]) -> Vec<usize> {
+    if shape.is_empty() {
+        return Vec::new();
+    }
+
+    let mut strides = vec![1; shape.len()];
+    let mut running = 1usize;
+    for idx in (0..shape.len()).rev() {
+        strides[idx] = running;
+        running = running.saturating_mul(shape[idx]);
+    }
+    strides
+}
