+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+pub enum KernelError {
+    Incompatible(TensorCompatError),
+}
+
+impl fmt::Display for KernelError {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        match self {
